INSERT INTO public.dosha_test_questions (part, "group", sort_order, text, options, tag_label) VALUES
('part1', NULL, 0, 'Sua maneira de se expressar é mais:', '[{"label":"Rápida, com gesticulação (movimento) ou, às vezes, um pouco rouca.","scores":{"v":2}},{"label":"Clara, intensa e, por vezes, crítica ou argumentativa.","scores":{"p":2}},{"label":"Lenta, suave ou reservada (prefiro ouvir).","scores":{"k":2}}]'::jsonb, NULL),
('part1', NULL, 1, 'Como você lida com mudanças inesperadas em sua rotina?', '[{"label":"Fico ansioso(a), inseguro(a), com medo ou dúvida.","scores":{"v":2,"agni_irregular":1}},{"label":"Fico estressado(a) e imediatamente busco a melhor solução e ordem.","scores":{"p":2}},{"label":"Fico resistente e prefiro manter o que é familiar e confortável.","scores":{"k":2}}]'::jsonb, NULL),
('part1', NULL, 2, 'Qual emoção você sente com mais frequência ou intensidade quando está sob estresse?', '[{"label":"Ansiedade, nervosismo ou medo de que algo ruim aconteça.","scores":{"v":2,"agni_irregular":1}},{"label":"Irritação, raiva ou impaciência com a lentidão dos outros.","scores":{"p":2,"agni_forte":1}},{"label":"Melancolia, apatia ou busca por conforto (comer, dormir).","scores":{"k":2,"agni_fraco":2}},{"label":"Oscilo entre ansiedade e frustração/raiva.","scores":{"v":1,"p":1}}]'::jsonb, NULL),
('part1', NULL, 3, 'Como está o fluxo de suas ideias e sua capacidade de concentração?', '[{"label":"Tenho muitas ideias e sou criativo(a), mas a mente está dispersa e me esqueço dos detalhes.","scores":{"v":2,"agni_irregular":1}},{"label":"Minha mente é focada, analítica e busca o discernimento rápido para resolver problemas.","scores":{"p":2,"agni_forte":1}},{"label":"Mente estável e calma, mas demoro para iniciar novos projetos (letargia mental).","scores":{"k":2}},{"label":"Mente agitada e analítica ao mesmo tempo (ansiedade com necessidade de controle).","scores":{"v":1,"p":1}},{"label":"Mente lenta para iniciar e dispersa para finalizar.","scores":{"v":1,"k":1}}]'::jsonb, NULL),
('part2', NULL, 0, 'Meu apetite é geralmente:', '[{"label":"Irregular, às vezes como, às vezes me esqueço de comer.","scores":{"v":2,"agni_irregular":2}},{"label":"Forte e intenso (fico irritado se não como na hora certa).","scores":{"p":2,"agni_forte":2}},{"label":"Fraco ou lento para aparecer, tenho peso no estômago.","scores":{"k":2,"agni_fraco":2}}]'::jsonb, NULL),
('part2', NULL, 1, 'O que você sente mais frequentemente após as refeições?', '[{"label":"Gases ou estufamento (espaço vazio e movimento no trato digestivo).","scores":{"v":2,"agni_irregular":2}},{"label":"Acidez ou queimação (fogo/calor).","scores":{"p":2,"agni_forte":2}},{"label":"Sonolência e peso na barriga.","scores":{"k":2,"v":1,"agni_fraco":2}},{"label":"Gases com queimação ou acidez.","scores":{"v":2,"p":2,"agni_irregular":1,"agni_forte":1}},{"label":"Peso e letargia com estufamento e gases.","scores":{"v":2,"k":2,"agni_fraco":1,"agni_irregular":1}}]'::jsonb, NULL),
('part2', NULL, 2, 'Sua capacidade de transformar o que come é:', '[{"label":"Irregular (digestão inconstante, ora rápida, ora lenta demais).","scores":{"v":1,"agni_irregular":1}},{"label":"Intensa (o alimento é queimado rápido e tenho muita fome logo depois).","scores":{"p":1,"agni_forte":1}},{"label":"Lenta e fraca (demora para sentir fome novamente).","scores":{"v":2,"k":2,"agni_fraco":1}},{"label":"Intensa e lenta (acidez e peso estomacal).","scores":{"p":2,"k":2}}]'::jsonb, NULL),
('part3', NULL, 0, 'Minha urina é:', '[{"label":"Escassa, posso segurar, faço pouco xixi.","scores":{"v":2,"agni_irregular":1}},{"label":"Amarelada escura ou quente, constante e abundante.","scores":{"p":2,"agni_forte":1}},{"label":"Com odor, posso ir pouco mas é volumosa.","scores":{"k":2,"agni_fraco":1}}]'::jsonb, NULL),
('part3', NULL, 1, 'Meu suor e odor corporal é:', '[{"label":"Quase não suo, e minha pele é seca.","scores":{"v":2}},{"label":"Suor excessivo, quente ou com odor forte/ácido.","scores":{"p":2}},{"label":"Suor moderado, pele oleosa ou com tendência a retenção de líquido.","scores":{"k":1}},{"label":"Pouco suor e pele quente e seca.","scores":{"v":1,"p":1}},{"label":"Suor quente, amarelado, oleoso e úmido.","scores":{"p":2,"k":2}}]'::jsonb, NULL),
('part3', NULL, 2, 'Minhas evacuações são tipicamente:', '[{"label":"Constipadas, secas, difíceis de eliminar.","scores":{"v":3}},{"label":"Soltas, com cheiro forte e tendência à diarreia.","scores":{"p":3}},{"label":"Grandes, pesadas, pastosas ou com muco.","scores":{"k":3}}]'::jsonb, NULL),
('part4', NULL, 0, 'Meu corpo tende a ser:', '[{"label":"Magro ou leve, assimétrico, com dificuldade em ganhar peso.","scores":{"v":2}},{"label":"Mediano, atlético, simétrico, ganha tônus com facilidade.","scores":{"p":3}},{"label":"Robusto, arredondado com facilidade em ganhar peso e dificuldade em perder.","scores":{"k":3}}]'::jsonb, NULL),
('part4', NULL, 1, 'Sinto minhas articulações e ossos com mais:', '[{"label":"Estalos, rigidez ou dor que muda de lugar, às vezes some.","scores":{"v":2}},{"label":"Inflamação articular, tendinite, dores quentes pulsantes.","scores":{"p":1}},{"label":"Peso, inchaço ou edemas, retendo líquido.","scores":{"k":1}}]'::jsonb, NULL),
('part4', NULL, 2, 'Minha pele é mais:', '[{"label":"Seca, fria e áspera (falta de umidade/nutrição).","scores":{"v":2,"agni_irregular":1}},{"label":"Sensível, com vermelhidão ou manchas e pintas.","scores":{"p":2,"agni_forte":1}},{"label":"Oleosa, fria e densa (untuosidade).","scores":{"k":2,"agni_fraco":1}}]'::jsonb, NULL),
('part4', NULL, 3, 'Saúde Íntima / Ciclo Menstrual:', '[{"label":"Ciclo irregular, cólicas fortes, pouco fluxo.","scores":{"v":2}},{"label":"Fluxo intenso, sangue bem vermelho, queimação ou TPM com irritação.","scores":{"p":2}},{"label":"Fluxo denso, retenção de líquido, cólica pesada e constante.","scores":{"k":2}},{"label":"Não menstruo / Menopausa / Sou homem.","scores":{}}]'::jsonb, NULL),
('part5', NULL, 0, 'Minha energia física e vigor são:', '[{"label":"Oscilantes, com picos e quedas, sentindo pouca vitalidade.","scores":{"v":2,"agni_irregular":1}},{"label":"Intensos, mas me sinto esgotado(a) se não descansar (alto metabolismo).","scores":{"p":2,"agni_forte":1}},{"label":"Estáveis, com grande resistência e paciência.","scores":{"k":2}}]'::jsonb, NULL),
('part5', NULL, 1, 'Em relação à minha saúde geral, eu:', '[{"label":"Adoeço facilmente, sinto que minha imunidade é frágil.","scores":{"v":2,"agni_irregular":1}},{"label":"Sou propenso(a) a infecções ou inflamações (ites).","scores":{"p":2,"agni_forte":1}},{"label":"Sou propenso(a) a muco, congestionamento, inchaço e edemas.","scores":{"k":2,"agni_fraco":1}}]'::jsonb, NULL),
('part6', NULL, 0, 'Meu sono costuma ser mais:', '[{"label":"Leve, com insônia ou dificuldade em manter o sono. Acordo facilmente.","scores":{"v":2,"agni_irregular":1}},{"label":"Penso muito pra dormir mas quando apago consigo aprofundar, posso acordar irritado.","scores":{"p":2,"agni_forte":1}},{"label":"Durmo com facilidade, sinto dificuldade em acordar ou tenho letargia.","scores":{"k":2,"agni_fraco":1}}]'::jsonb, NULL),
('part6', NULL, 1, 'Meu ritmo e horários diários (comer, dormir) são:', '[{"label":"Irregulares e inconstantes (não tenho horários fixos).","scores":{"v":2,"agni_irregular":1}},{"label":"Intensos, acelerados e cheios de compromissos.","scores":{"p":2,"agni_forte":1}},{"label":"Lentos, estáveis e busco o conforto.","scores":{"k":2,"agni_fraco":1}}]'::jsonb, NULL),
('part6', NULL, 2, 'Meu estilo de trabalho ou hobbies é:', '[{"label":"Criativo, envolvo-me em multitarefas e adoro viajar.","scores":{"v":1}},{"label":"Competitivo, focado em resultados e liderança.","scores":{"p":1}},{"label":"Estável, prefiro ambientes acolhedores e familiares.","scores":{"k":2}},{"label":"Multitarefas e competitivo.","scores":{"v":2,"p":2}}]'::jsonb, NULL),
('part6', NULL, 3, 'Quando você tem um tempo livre para lazer, que tipo de energia você prefere gastar?', '[{"label":"Gosto de usar minha imaginação e criatividade. Prefiro atividades leves, artísticas ou mentais.","scores":{"v":2}},{"label":"Gosto de atividades que exigem foco, disputa e desafio, gosto de testar meus limites.","scores":{"p":2}},{"label":"Gosto mais de ficar em casa e relaxar, optar por ler ou assistir algo, passear levemente.","scores":{"k":2}}]'::jsonb, NULL),
('part7', NULL, 0, 'O clima que mais me incomoda ou agrava minha saúde é:', '[{"label":"Frio, vento e tempo seco.","scores":{"v":1,"k":1}},{"label":"Calor, sol forte ou tempo quente em geral.","scores":{"p":1,"k":1}},{"label":"Tempo úmido, chuvoso e frio.","scores":{"v":1,"k":1}}]'::jsonb, NULL),
('part7', NULL, 1, 'Quando preciso tomar decisões, eu as tomo de forma:', '[{"label":"Confusa ou indecisa, mudando de ideia facilmente.","scores":{"v":2}},{"label":"Penetrante, com clareza e convicção (discernimento abundante).","scores":{"p":2}},{"label":"Lenta, com resistência ou por falta de clareza.","scores":{"k":2}}]'::jsonb, NULL),
('part7', NULL, 2, 'Meu corpo se sente mais frequentemente:', '[{"label":"Frio ou com as extremidades frias (mãos e pés).","scores":{"v":2}},{"label":"Quente ou com tendência a calor nas extremidades.","scores":{"p":2}},{"label":"Frio, mas com sensação de densidade ou peso.","scores":{"k":2}}]'::jsonb, NULL),
('part7', NULL, 3, 'Em termos de constituição física, eu sou mais:', '[{"label":"Alto(a), magro(a), com ossos proeminentes.","scores":{"v":2}},{"label":"De altura média, atlético(a) ou com densidade muscular.","scores":{"p":2}},{"label":"Robusto(a), com ganho de peso, com estrutura larga.","scores":{"k":3}}]'::jsonb, NULL),
